SET NAMES utf8mb4;

-- =============================================
-- PARTE A: Inserir medicamentos na pgx_drug_genes
-- =============================================


-- =============================================
-- PARTE B: Detalhes (principais)
-- =============================================

VALUES ('Diazepam', (SELECT id FROM pgx_drug_classes WHERE code='psiq_neuro' LIMIT 1), 'Valium®, Compaz®, Uni-diazepax®', 'O diazepam é um benzodiazepínico de longa ação utilizado para ansiedade, convulsões, espasmo muscular e sedação. É metabolizado pelo CYP2C19 (via principal) e CYP3A4 (secundária). Em metabolizadores rápidos do CYP2C19, a duração pode ser MENOR.', 'CYP2C19 *1/*17 (CT) = METABOLIZADOR RÁPIDO. O diazepam pode ser eliminado mais rapidamente, com duração de ação potencialmente MENOR. CYP3A4 (GG) = normal.', 'rs12248560', '10', 'CYP2C19', 'Europeia', 'CYP2C19 e Diazepam:\n- *1/*1 = Normal\n- *1/*17 = Metabolismo aumentado (duração pode ser menor)\n- *17/*17 = Duração significativamente menor\n- *2/*2 = Lento (duração prolongada)', 'CYP2C19 rápido (*1/*17). Diazepam pode ter duração MENOR que esperado. Se for necessário benzodiazepínico, considerar: 1) Dose mais frequente, 2) Lorazepam como alternativa (NÃO depende de CYP), 3) Oxazepam (NÃO depende de CYP). Para sedação na cirurgia, midazolam + monitoramento (CYP3A5 expressor parcial reduz duração também).', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();

VALUES ('Diclofenaco', (SELECT id FROM pgx_drug_classes WHERE code='analgesico' LIMIT 1), 'Voltaren®, Belfaren®, Fenaren®, Biofenac®, Voltaflex®', 'O diclofenaco é um AINE potente utilizado para dor, inflamação e artrite. É metabolizado pelo CYP2C9. Em metabolizadores lentos, risco de sangramento e nefrotoxicidade.', 'CYP2C9 (CC = *1/*1) = Metabolizador NORMAL. Diclofenaco processado adequadamente.', 'rs1799853', '10', 'CYP2C9', 'Europeia', 'CYP2C9 e Diclofenaco:\n- CC = Normal\n- CT = Intermediário (monitorar)\n- TT = Lento (risco)', 'CYP2C9 normal. Diclofenaco dose padrão. Pode ser opção anti-inflamatória para dor pós-operatória se AINEs forem indicados.', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();

VALUES ('Dexlansoprazol', (SELECT id FROM pgx_drug_classes WHERE code='gastro' LIMIT 1), 'Dexilant®, Kapidex®', 'O dexlansoprazol é o enantiômero R do lansoprazol com liberação dupla. Dependente do CYP2C19 (como lansoprazol).', 'CYP2C19 *1/*17 = metabolizador rápido. Eficácia possivelmente reduzida. Preferir rabeprazol.', 'rs12248560', '10', 'CYP2C19', 'Europeia', 'CYP2C19 e Dexlansoprazol:\n- Similar ao lansoprazol em dependência do CYP2C19\n- *1/*17 = Eficácia reduzida', 'CYP2C19 rápido. Dexlansoprazol pode ter eficácia reduzida. PREFERIR RABEPRAZOL.', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();

VALUES ('Dexmetilfenidato', (SELECT id FROM pgx_drug_classes WHERE code='psiq_neuro' LIMIT 1), 'Ritalina LA®, Focalin®', 'O dexmetilfenidato é o enantiômero D do metilfenidato, mais ativo. NÃO depende do CYP2D6 (metabolizado por esterases). ADRA2A modula resposta.', 'ADRA2A (rs1800544) N/D. Mesma análise do metilfenidato — SLC6A2 GA + DRD1 TT = resposta VARIÁVEL. NÃO depende do CYP2D6.', 'rs1800544', '10', 'ADRA2A', 'Europeia', 'ADRA2A: N/D\nSLC6A2 rs5569: GA = Variável\nDRD1 rs4532: TT = Função executiva alterada\n\nNÃO depende de CYP2D6.', 'Mesma recomendação do metilfenidato: resposta variável, monitorar eficácia. NÃO depende do CYP2D6 (vantagem). Ritalina LA é formulação de liberação prolongada do metilfenidato (contém D e L).', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();